#include<bits/stdc++.h>
using namespace std;
long long minn, minx;
long long t[200051];
long long p[200051];
int q, n;
long long dp[200051];
int main() {
	minn = 1e18;
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> t[i];
		if (t[i] < minn) {
			minx = i;
			minn = t[i];
		}
	}
	for (int i = 1; i <= n; i++) {
		cin >> p[i];
	}
	//cout<<minn;
	dp[minx]=t[minx];
	minx++;
	for (int i = 2; i <= n; i++) {
		if (minx == n + 1) {
			minx = 1;
		}
		if (minx != 1) dp[minx] = min(t[minx], dp[(minx - 1)] + p[minx - 1]);
		else dp[minx] = min(t[minx], dp[n] + p[n]);
		minx++;
	}
	cin>>q;
	while(q--){
		int x;
		cin>>x;
		cout<<dp[x]<<"\n";
	}
	return 0;
}
